// Filtra scenarios ATIVOS
const response = $input.first().json;
const scenarios = response.scenarios || [];

const active = scenarios.filter(s => s.isPaused === false && s.islinked === true);

if (active.length === 0) {
  return [{ json: { skip: true, scenarioId: null, scenarioName: null } }];
}

return active.map(s => ({
  json: {
    scenarioId: s.id,
    scenarioName: s.name
  }
}));

// Agrupa dlqs por scenario (preserva nome do scenario)
// Filtra dlqs já auto-resolvidas (campo resolved: boolean da Make API)
const items = $input.all();
const dlqsByScenario = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const allDlqs = item.json?.dlqs || [];

  // Filtro: apenas dlqs NÃO resolvidas (resolved === false ou undefined)
  const dlqs = allDlqs.filter(d => d.resolved !== true);

  if (dlqs.length === 0) continue;

  const scenarioInfo = $('Filter Active Scenarios').all()[i]?.json || {};

  dlqsByScenario.push({
    scenarioId: scenarioInfo.scenarioId,
    scenarioName: scenarioInfo.scenarioName,
    count: dlqs.length,
    lastError: dlqs[0]?.reason || dlqs[0]?.detail || 'unknown',
    incompleteExecutionId: dlqs[0]?.id || null
  });
}

return [{ json: { makeIncomplete: dlqsByScenario } }];

// Consolida erros das 4 fontes em payload único
const sinceUnix = $('Set Timestamps').first().json.sinceUnix;
const nowBR = $('Set Timestamps').first().json.nowBR;

// Coleta de cada fonte (nodes nomeados)
const hetznerRaw = $('n8n Hetzner Errors').first()?.json?.data || [];
const oracleRaw = $('n8n Oracle Errors').first()?.json?.data || [];
const railwayRaw = $('n8n Railway Errors').first()?.json?.data || [];
const makeRaw = $('Aggregate Make').first()?.json?.makeIncomplete || [];

// URLs base
const urls = {
  hetzner: 'https://workflows.coletiv.me',
  oracle: 'https://workflowsoracle.coletiv.me',
  railway: 'https://primary-production-af84.up.railway.app',
  makeBase: 'https://eu1.make.com'
};

// Filtra n8n por janela 24h e agrupa por workflowId
function processN8n(executions, baseUrl, sourceName) {
  if (!Array.isArray(executions)) return [];

  const recent = executions.filter(e => {
    const stoppedAt = e.stoppedAt ? new Date(e.stoppedAt).getTime() / 1000 : 0;
    return stoppedAt >= sinceUnix;
  });

  const byWorkflow = {};
  for (const exec of recent) {
    const wfId = exec.workflowId;
    const wfName = exec.workflowData?.name || exec.workflow?.name || `Workflow ${wfId}`;
    if (!byWorkflow[wfId]) {
      byWorkflow[wfId] = {
        workflowId: wfId,
        workflowName: wfName,
        count: 0,
        lastErrorMessage: null,
        lastExecutionId: null,
        source: sourceName,
        link: `${baseUrl}/workflow/${wfId}`
      };
    }
    byWorkflow[wfId].count += 1;
    if (!byWorkflow[wfId].lastExecutionId) {
      byWorkflow[wfId].lastExecutionId = exec.id;
      byWorkflow[wfId].lastErrorMessage = exec.data?.resultData?.error?.message || 'Sem mensagem';
      byWorkflow[wfId].executionLink = `${baseUrl}/workflow/${wfId}/executions/${exec.id}`;
    }
  }
  return Object.values(byWorkflow);
}

const hetznerErrors = processN8n(hetznerRaw, urls.hetzner, 'Hetzner');
const oracleErrors = processN8n(oracleRaw, urls.oracle, 'Oracle');
const railwayErrors = processN8n(railwayRaw, urls.railway, 'Railway');

// Make: enriquecer com link
const makeErrors = makeRaw.map(m => ({
  ...m,
  source: 'Make',
  link: `${urls.makeBase}/scenarios/${m.scenarioId}/edit`,
  incompleteLink: `${urls.makeBase}/scenarios/${m.scenarioId}/incomplete-executions`
}));

const totalErrors = 
  hetznerErrors.reduce((s, w) => s + w.count, 0) +
  oracleErrors.reduce((s, w) => s + w.count, 0) +
  railwayErrors.reduce((s, w) => s + w.count, 0) +
  makeErrors.reduce((s, w) => s + w.count, 0);

const totalWorkflows = 
  hetznerErrors.length + oracleErrors.length + railwayErrors.length + makeErrors.length;

return [{
  json: {
    timestamp: nowBR,
    totalErrors,
    totalWorkflows,
    shouldAlert: totalErrors > 0,
    sources: {
      hetzner: hetznerErrors,
      oracle: oracleErrors,
      railway: railwayErrors,
      make: makeErrors
    }
  }
}];

// Formata mensagem Telegram (HTML mode)
const data = $input.first().json;
const { timestamp, totalErrors, totalWorkflows, sources } = data;

let msg = `<b>🚨 Daily Ops Health Check</b>\n`;
msg += `<i>${timestamp} BRT — últimas 24h</i>\n\n`;
msg += `<b>Total:</b> ${totalErrors} erros em ${totalWorkflows} workflows\n\n`;

function esc(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function formatSection(title, emoji, items) {
  if (items.length === 0) return '';
  let section = `<b>${emoji} ${title}</b> (${items.length})\n`;
  for (const w of items.slice(0, 10)) {
    const name = esc((w.workflowName || w.scenarioName || 'unknown').substring(0, 60));
    const link = w.executionLink || w.incompleteLink || w.link;
    section += `• <a href="${link}">${name}</a> — ${w.count}x\n`;
    const errMsg = (w.lastErrorMessage || w.lastError || '').toString().substring(0, 120);
    if (errMsg) {
      section += `  <i>↳ ${esc(errMsg)}</i>\n`;
    }
  }
  if (items.length > 10) section += `  ... +${items.length - 10} outros\n`;
  return section + '\n';
}

msg += formatSection('n8n Hetzner', '🔵', sources.hetzner);
msg += formatSection('n8n Oracle', '🟠', sources.oracle);
msg += formatSection('n8n Railway', '🟣', sources.railway);
msg += formatSection('Make Incomplete', '🔴', sources.make);

return [{ json: { telegramMessage: msg.trim() } }];

